import Header from './Header';
import Content from './Content';
import Footer from './Footer';
import Additems from './Additems';
import { useState } from 'react';

function App() {
  const[items,setItems]=useState([
    {id:1,activity:"Code Every Day",checked:true},
    {id:2,activity:"play cricket ",checked:false},
    {id:3,activity:"Pratice Fluency",checked:false}])
    const handleChange = (id)=>
    {
      const changeItems =items.map(items => (items.id==id) ?{...items,checked:!items.checked}:items);
      setItems(changeItems);
    }
    const changeDelete=(id)=>
    {
      const deleteAll=items.filter(items =>items.id!==id);
      setItems(deleteAll);
    }
    const addItem=(activity)=>{
      //const id=(items.length)?items[items.length -1].id+1:1
      const id=<items className="length">\</items>
      const addNewItem={id,activity,checked:false}
      const listItem=[...items,addNewItem]
      setItems(listItem)
    }
    const [newItem,setNewItem]=useState('')
    const handleSumbit=(e)=>{
      e.preventDefault();
      if(!newItem) return;
      console.log(newItem)
      addItem(newItem)
      setNewItem('')
    }
  return (
    <div>
    <Header title="To-Do Lists"/>
    <Additems newItem={newItem} setNewItem={setNewItem} handleSumbit={handleSumbit}/>
    <Content items={items} changeDelete={changeDelete} handleChange={handleChange}/>
    <Footer items={items}/>
    </div>
  );
}

export default App;
